import{_ as r,I as o,o as i,c as l,aq as p,J as e}from"./chunks/framework.kV0qpqqq.js";const x=JSON.parse('{"title":"其他篇","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/astrobox/AstroboxV1其他篇.md","filePath":"Guides/astrobox/AstroboxV1其他篇.md","lastUpdated":1773512079000}'),n={name:"Guides/astrobox/AstroboxV1其他篇.md"};function c(b,a,h,d,m,_){const t=o("NolebaseGitContributors"),s=o("NolebaseGitChangelog");return i(),l("div",null,[a[0]||(a[0]=p('<h1 id="其他篇" tabindex="-1">其他篇 <a class="header-anchor" href="#其他篇" aria-label="Permalink to “其他篇”">​</a></h1><h2 id="q1-遇到未知问题怎么办" tabindex="-1">Q1：遇到未知问题怎么办？ <a class="header-anchor" href="#q1-遇到未知问题怎么办" aria-label="Permalink to “Q1：遇到未知问题怎么办？”">​</a></h2><p><mark>好的办法是提取应用运行 log 并发送在群中。</mark></p><h3 id="logs-提取方式" tabindex="-1">Logs 提取方式 <a class="header-anchor" href="#logs-提取方式" aria-label="Permalink to “Logs 提取方式”">​</a></h3><p>电脑用户可以更新至 1.0.1 以后版本直接在设置里打开，也可以从以下地址中自行查找：</p><p>安卓：在原生文件app直接选择astrobox（可以通过 MT 等工具搜索到原生的文件并打开，在左上角可以切换到 AstroBox 的选项卡，里面的 Logs 文件夹就是我们要的）</p><p>Windows：</p><blockquote><p>C:\\Users\\你的用户名\\AppData\\Local\\moe.astralsight.astrobox</p></blockquote><p>Mac：</p><blockquote><p>/Users（或译为用户）/你的用户名/Library（或译为资源库，需要快捷键 command+shift+.才会出现）/Logs/moe.astralsight.astrobox/</p></blockquote><p>Linux：</p><blockquote><p>/home/你的用户名/.local/share/moe.astralsight.astrobox/</p></blockquote><h3 id="config-存储位置" tabindex="-1">Config 存储位置 <a class="header-anchor" href="#config-存储位置" aria-label="Permalink to “Config 存储位置”">​</a></h3><p>Windows：</p><blockquote><p>C:\\Users\\用户名\\AppData\\Roaming\\moe.astralsight.astrobox</p></blockquote><p>Mac：</p><blockquote><p>/Users（或译为用户）/你的用户名/Library/Application Support/moe.astralsight.astrobox</p></blockquote><h2 id="q2-你们的群在哪" tabindex="-1">Q2：你们的群在哪 <a class="header-anchor" href="#q2-你们的群在哪" aria-label="Permalink to “Q2：你们的群在哪”">​</a></h2><p>QQ 交流群：920456907</p><p>:::note</p><p>本教程由Yulimfish，川.，wuhaiqi等人编写，本人（lladlam）仅为第三方转载，著作权归Yulimfish，川.，wuhaiqi等人所有</p><p>:::</p>',22)),e(t),e(s)])}const g=r(n,[["render",c]]);export{x as __pageData,g as default};
